import{_ as i,o as s,c as a,a2 as t}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Services","description":"","frontmatter":{},"headers":[],"relativePath":"fr/api/services.md","filePath":"fr/api/services.md"}'),r={name:"fr/api/services.md"};function n(l,e,o,c,d,p){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h1><p>Tous les services de Clearance vivent dans <code>src/Services/</code> et sont résolus depuis le conteneur, ex. <code>app(ContextService::class)</code>. Ils constituent la couche à privilégier depuis les contrôleurs, policies, et jobs — partout où le modèle <code>User</code> peut ne pas utiliser le trait <code>HasClearance</code>.</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code> (<code>src/Services/ContextService.php</code>) est le moteur derrière l&#39;autorisation contextuelle. La <a href="/clearance-docs/fr/api/facade.html">facade <code>Clearance</code></a> et le trait <code>HasClearance</code> délèguent tous deux vers lui.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p><code>resolveFor()</code> construit son résultat selon une priorité à 3 sources :</p><ol><li>Attributions de rôle contextuelles</li><li>Attributions de rôle globales</li><li>Surcharges par contexte (<code>forced_on</code> ajoute, <code>forced_off</code> l&#39;emporte toujours)</li></ol><p>Voir <a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a> pour la présentation conceptuelle de cette priorité.</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code> (<code>src/Services/RoleService.php</code>) gère les rôles plafonds.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Méthode</th><th>Description</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>Définit un plafond : les permissions excédentaires sur <code>$childRole</code> au-delà de l&#39;ensemble du parent sont silencieusement retirées. Lève <code>ClearanceScopeViolationException</code> si l&#39;enfant est déjà un parent, ou si le parent est déjà un enfant.</td></tr><tr><td><code>removeParent($childRole)</code></td><td>Retire la relation de plafond.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Un plafond ne fait que retirer — il n&#39;accorde jamais. Un rôle parent permissif ne donne, par lui-même, aucune permission à l&#39;enfant. Retirer une permission d&#39;un rôle parent propage automatiquement cette suppression à chaque rôle enfant.</p></div><p>Voir <a href="/clearance-docs/fr/features/roles.html">Rôles</a> pour le concept de rôle plafond en détail.</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code> (<code>src/Services/PermissionService.php</code>) alimente le CRUD du panneau Permissions.</p><p>Il applique la convention de nommage <code>group-action</code>, contrôlée par les clés de configuration <code>enforce_naming_convention</code> et <code>naming_separator</code>, et protège l&#39;espace de noms de permission <code>clearance-*</code> contre toute création, renommage, ou suppression en dehors du flux d&#39;installation.</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code> (<code>src/Services/GuardService.php</code>) alimente le CRUD du panneau Gardes.</p><p>Il injecte les gardes stockés en base de données dans <code>auth.guards</code> au démarrage, filtrés par la clé de configuration <code>allowed_guard_drivers</code> — un driver non listé est ignoré avec un avertissement dans les logs plutôt que de corrompre la configuration d&#39;authentification.</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code> (<code>src/Services/MetaService.php</code>) lit et écrit <code>clr_meta</code> (nom d&#39;affichage, description, icône SVG assainie, couleur) pour un sujet rôle ou garde. Il alimente l&#39;éditeur de métadonnées d&#39;affichage du panneau Paramètres.</p><p>Les icônes SVG passent par <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code> (un assainisseur en liste blanche) à la fois avant le stockage et au moment du rendu.</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code> (<code>src/Services/UserClearanceService.php</code>) alimente le panneau du module Utilisateurs :</p><ul><li>Attribution de rôle globale</li><li>Attribution de rôle contextuelle (via <code>UserRoleContext</code>)</li><li>Surcharges de permission par contexte (via <code>UserContextPermissionOverride</code>, <code>forced_on</code> / <code>forced_off</code>)</li><li>Retrait d&#39;attributions, ce qui propage la suppression des surcharges</li></ul><p>Il applique un plafond de privilège : un acteur non-<code>super_admin</code> ne peut pas modifier ses propres attributions, et ne peut pas accorder une permission qu&#39;il ne détient pas lui-même. Voir <a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a> et <a href="/clearance-docs/fr/features/users.html">Utilisateurs</a>.</p><h2 id="exceptions" tabindex="-1">Exceptions <a class="header-anchor" href="#exceptions" aria-label="Permalink to &quot;Exceptions&quot;">​</a></h2><p>Toutes dans <code>src/Exceptions/</code> :</p><table tabindex="0"><thead><tr><th>Exception</th><th>Levée quand</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>Une valeur invalide ou mal configurée de <code>config/clearance.php</code> est lue (ex. un <code>naming_separator</code> incorrect).</td></tr><tr><td><code>ClearanceNamingException</code></td><td>Un nom de permission viole la convention de nommage <code>group-action</code> alors que le contrôle est activé.</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>Une tentative est faite de modifier une permission <code>clearance-*</code> protégée, ou une ressource verrouillée, en dehors du flux d&#39;installation.</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>Une relation de rôle plafond invalide (un parent essayant de devenir enfant, ou inversement), ou une incohérence de portée.</td></tr></tbody></table><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/api/facade.html">Facade</a> — le wrapper en appel statique autour de <code>ContextService</code>.</li><li><a href="/clearance-docs/fr/api/traits-directives.html">Traits &amp; Directives</a> — les équivalents en méthode d&#39;instance et directive Blade.</li><li><a href="/clearance-docs/fr/api/artisan-commands.html">Commandes Artisan</a> — <code>clearance:install</code> et <code>clearance:backfill</code>, qui amorcent les données sur lesquelles ces services opèrent.</li></ul>',32)])])}const k=i(r,[["render",n]]);export{u as __pageData,k as default};
